import{_ as a,o as s,c as n,ai as l}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Gateway 网关架构","description":"","frontmatter":{"read_when":["正在开发 Gateway 网关协议、客户端或传输层"],"summary":"WebSocket Gateway 网关架构、组件和客户端流程","title":"Gateway 网关架构","x-i18n":{"generated_at":"2026-02-03T07:45:55Z","model":"claude-opus-4-5","provider":"pi","source_hash":"c636d5d8a5e628067432b30671466309e3d630b106d413f1708765bf2a9399a1","source_path":"concepts/architecture.md","workflow":15}},"headers":[],"relativePath":"zh-CN/concepts/architecture.md","filePath":"zh-CN/concepts/architecture.md","lastUpdated":null}'),c={name:"zh-CN/concepts/architecture.md"};function i(o,e,t,d,r,p){return s(),n("div",null,[...e[0]||(e[0]=[l(`<h1 id="gateway-网关架构" tabindex="-1"><a class="header-anchor" href="#gateway-网关架构">#</a> Gateway 网关架构</h1><p>最后更新：2026-01-22</p><h2 id="概述" tabindex="-1"><a class="header-anchor" href="#概述">#</a> 概述</h2><ul><li>单个长期运行的 <strong>Gateway 网关</strong>拥有所有消息平台（通过 Baileys 的 WhatsApp、通过 grammY 的 Telegram、Slack、Discord、Signal、iMessage、WebChat）。</li><li>控制平面客户端（macOS 应用、CLI、Web 界面、自动化）通过配置的绑定主机（默认 <code>127.0.0.1:18789</code>）上的 <strong>WebSocket</strong> 连接到 Gateway 网关。</li><li><strong>节点</strong>（macOS/iOS/Android/无头设备）也通过 <strong>WebSocket</strong> 连接，但声明 <code>role: node</code> 并带有明确的能力/命令。</li><li>每台主机一个 Gateway 网关；它是唯一打开 WhatsApp 会话的位置。</li><li><strong>canvas 主机</strong>（默认 <code>18793</code>）提供智能体可编辑的 HTML 和 A2UI。</li></ul><h2 id="组件和流程" tabindex="-1"><a class="header-anchor" href="#组件和流程">#</a> 组件和流程</h2><h3 id="gateway-网关-守护进程" tabindex="-1"><a class="header-anchor" href="#gateway-网关-守护进程">#</a> Gateway 网关（守护进程）</h3><ul><li>维护提供商连接。</li><li>暴露类型化的 WS API（请求、响应、服务器推送事件）。</li><li>根据 JSON Schema 验证入站帧。</li><li>发出事件如 <code>agent</code>、<code>chat</code>、<code>presence</code>、<code>health</code>、<code>heartbeat</code>、<code>cron</code>。</li></ul><h3 id="客户端-mac-应用-cli-web-管理" tabindex="-1"><a class="header-anchor" href="#客户端-mac-应用-cli-web-管理">#</a> 客户端（mac 应用 / CLI / web 管理）</h3><ul><li>每个客户端一个 WS 连接。</li><li>发送请求（<code>health</code>、<code>status</code>、<code>send</code>、<code>agent</code>、<code>system-presence</code>）。</li><li>订阅事件（<code>tick</code>、<code>agent</code>、<code>presence</code>、<code>shutdown</code>）。</li></ul><h3 id="节点-macos-ios-android-无头设备" tabindex="-1"><a class="header-anchor" href="#节点-macos-ios-android-无头设备">#</a> 节点（macOS / iOS / Android / 无头设备）</h3><ul><li>以 <code>role: node</code> 连接到<strong>同一个 WS 服务器</strong>。</li><li>在 <code>connect</code> 中提供设备身份；配对是<strong>基于设备</strong>的（角色为 <code>node</code>），批准存储在设备配对存储中。</li><li>暴露命令如 <code>canvas.*</code>、<code>camera.*</code>、<code>screen.record</code>、<code>location.get</code>。</li></ul><p>协议详情：</p><ul><li><a href="/docs/gateway/protocol">Gateway 网关协议</a></li></ul><h3 id="webchat" tabindex="-1"><a class="header-anchor" href="#webchat">#</a> WebChat</h3><ul><li>静态界面，使用 Gateway 网关 WS API 获取聊天历史和发送消息。</li><li>在远程设置中，通过与其他客户端相同的 SSH/Tailscale 隧道连接。</li></ul><h2 id="连接生命周期-单个客户端" tabindex="-1"><a class="header-anchor" href="#连接生命周期-单个客户端">#</a> 连接生命周期（单个客户端）</h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client                    Gateway</span></span>
<span class="line"><span>  |                          |</span></span>
<span class="line"><span>  |---- req:connect --------&gt;|</span></span>
<span class="line"><span>  |&lt;------ res (ok) ---------|   (or res error + close)</span></span>
<span class="line"><span>  |   (payload=hello-ok carries snapshot: presence + health)</span></span>
<span class="line"><span>  |                          |</span></span>
<span class="line"><span>  |&lt;------ event:presence ---|</span></span>
<span class="line"><span>  |&lt;------ event:tick -------|</span></span>
<span class="line"><span>  |                          |</span></span>
<span class="line"><span>  |------- req:agent -------&gt;|</span></span>
<span class="line"><span>  |&lt;------ res:agent --------|   (ack: {runId,status:&quot;accepted&quot;})</span></span>
<span class="line"><span>  |&lt;------ event:agent ------|   (streaming)</span></span>
<span class="line"><span>  |&lt;------ res:agent --------|   (final: {runId,status,summary})</span></span>
<span class="line"><span>  |                          |</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h2 id="线路协议-摘要" tabindex="-1"><a class="header-anchor" href="#线路协议-摘要">#</a> 线路协议（摘要）</h2><ul><li>传输：WebSocket，带 JSON 载荷的文本帧。</li><li>第一帧<strong>必须</strong>是 <code>connect</code>。</li><li>握手后： <ul><li>请求：<code>{type:&quot;req&quot;, id, method, params}</code> → <code>{type:&quot;res&quot;, id, ok, payload|error}</code></li><li>事件：<code>{type:&quot;event&quot;, event, payload, seq?, stateVersion?}</code></li></ul></li><li>如果设置了 <code>OPENSOUL_GATEWAY_TOKEN</code>（或 <code>--token</code>），<code>connect.params.auth.token</code> 必须匹配，否则套接字关闭。</li><li>有副作用的方法（<code>send</code>、<code>agent</code>）需要幂等键以安全重试；服务器保持短期去重缓存。</li><li>节点必须在 <code>connect</code> 中包含 <code>role: &quot;node&quot;</code> 以及能力/命令/权限。</li></ul><h2 id="配对-本地信任" tabindex="-1"><a class="header-anchor" href="#配对-本地信任">#</a> 配对 + 本地信任</h2><ul><li>所有 WS 客户端（操作员 + 节点）在 <code>connect</code> 时包含<strong>设备身份</strong>。</li><li>新设备 ID 需要配对批准；Gateway 网关为后续连接颁发<strong>设备令牌</strong>。</li><li><strong>本地</strong>连接（loopback 或 Gateway 网关主机自身的 tailnet 地址）可以自动批准以保持同主机用户体验流畅。</li><li><strong>非本地</strong>连接必须签名 <code>connect.challenge</code> nonce 并需要明确批准。</li><li>Gateway 网关认证（<code>gateway.auth.*</code>）仍适用于<strong>所有</strong>连接，无论本地还是远程。</li></ul><p>详情：<a href="/docs/gateway/protocol">Gateway 网关协议</a>、<a href="/docs/channels/pairing">配对</a>、<a href="/docs/gateway/security/index">安全</a>。</p><h2 id="协议类型和代码生成" tabindex="-1"><a class="header-anchor" href="#协议类型和代码生成">#</a> 协议类型和代码生成</h2><ul><li>TypeBox 模式定义协议。</li><li>从这些模式生成 JSON Schema。</li><li>从 JSON Schema 生成 Swift 模型。</li></ul><h2 id="远程访问" tabindex="-1"><a class="header-anchor" href="#远程访问">#</a> 远程访问</h2><ul><li>推荐：Tailscale 或 VPN。</li><li>替代方案：SSH 隧道<div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 18789:127.0.0.1:18789</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li>相同的握手 + 认证令牌适用于隧道连接。</li><li>远程设置中可以为 WS 启用 TLS + 可选的证书固定。</li></ul><h2 id="操作快照" tabindex="-1"><a class="header-anchor" href="#操作快照">#</a> 操作快照</h2><ul><li>启动：<code>opensoul gateway</code>（前台，日志输出到 stdout）。</li><li>健康检查：通过 WS 的 <code>health</code>（也包含在 <code>hello-ok</code> 中）。</li><li>监控：使用 launchd/systemd 自动重启。</li></ul><h2 id="不变量" tabindex="-1"><a class="header-anchor" href="#不变量">#</a> 不变量</h2><ul><li>每台主机恰好一个 Gateway 网关控制单个 Baileys 会话。</li><li>握手是强制的；任何非 JSON 或非 connect 的第一帧都会导致硬关闭。</li><li>事件不会重放；客户端必须在出现间隙时刷新。</li></ul>`,30)])])}const b=a(c,[["render",i]]);export{u as __pageData,b as default};
